#include<bits/stdc++.h>
using namespace std;
long long s,t,n,a[101][101],m,d;
bool b[101][101],v[101];
long long dfs(long long x,long long y){
    v[x]=1;
	if(x==t){
		return y;
	}
	else{
		long long ans=1e18;
		for(long long i=1;i<=n;i++){
			if(a[x][i]&&!v[i]){
				if(b[x][i]){
					ans=min(dfs(i,a[x][i]+y),ans);
				}else{
					ans=min(dfs(i,y),ans);
				}
			}
		}
        v[x]=0;
		return ans;
	}
}
int main(){
	cin>>n;
	cin>>m;
	for(long long i=1;i<=m;i++){
		long long x,y,z;
		cin>>x>>y>>z;
		a[x][y]=z;
        a[y][x]=z;
	}
	cin>>d;
	for(long long i=1;i<=d;i++){
		long long x,y;
		cin>>x>>y;
		b[x][y]=1;
	}
	cin>>s>>t;
	cout<<dfs(s,0);
	return 0;
}
